import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getChannels, deleteChannel } from '../../services/api';

const AdminPanel = () => {
  const [channels, setChannels] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadChannels();
  }, []);

  const loadChannels = async () => {
    try {
      const data = await getChannels({});
      setChannels(data);
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id, name) => {
    if (window.confirm(`¿Eliminar "${name}"?`)) {
      try {
        await deleteChannel(id);
        setChannels(channels.filter(c => c.id !== id));
      } catch (error) {
        alert('Error al eliminar');
      }
    }
  };

  if (loading) return <div className="p-8 text-white">Cargando...</div>;

  return (
    <div className="p-8 text-white">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold">Panel de Administración</h1>
        <div className="flex gap-3">
          <Link
            to="/admin/import-m3u"
            className="bg-blue-600 hover:bg-blue-700 px-4 py-2 rounded font-medium"
          >
            📋 Importar M3U
          </Link>
          <Link
            to="/admin/add-channel"
            className="bg-red-600 hover:bg-red-700 px-4 py-2 rounded font-medium"
          >
            + Agregar Canal
          </Link>
        </div>
      </div>

      <div className="bg-gray-800 rounded-lg overflow-hidden">
        <div className="p-4 bg-gray-700 flex justify-between items-center">
          <h2 className="text-xl font-semibold">Canales y Radio ({channels.length})</h2>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-700">
              <tr>
                <th className="p-3 text-left">Canal</th>
                <th className="p-3 text-left">Categoría</th>
                <th className="p-3 text-left">País</th>
                <th className="p-3 text-left">URL</th>
                <th className="p-3 text-left">Acciones</th>
              </tr>
            </thead>
            <tbody>
              {channels.map(channel => (
                <tr key={channel.id} className="border-t border-gray-700 hover:bg-gray-750">
                  <td className="p-3">
                    <div className="flex items-center gap-3">
                      {channel.logo ? (
                        <img
                          src={channel.logo}
                          alt={channel.name}
                          className="w-10 h-10 object-contain bg-white rounded p-1"
                          onError={(e) => e.target.style.display = 'none'}
                        />
                      ) : (
                        <div className="w-10 h-10 bg-gray-600 rounded flex items-center justify-center">
                          {channel.category === 'Radio' ? '📻' : '📺'}
                        </div>
                      )}
                      <span className="font-medium">{channel.name}</span>
                    </div>
                  </td>
                  <td className="p-3">
                    <span className="bg-red-600 px-2 py-1 rounded text-xs">{channel.category}</span>
                  </td>
                  <td className="p-3 text-gray-400">{channel.country}</td>
                  <td className="p-3">
                    <span className="text-xs text-gray-500 truncate block max-w-xs">{channel.stream_url}</span>
                  </td>
                  <td className="p-3">
                    <div className="flex gap-2">
                      <Link
                        to={`/player/channel/${channel.id}`}
                        className="bg-green-600 hover:bg-green-700 px-2 py-1 rounded text-xs"
                      >
                        Ver
                      </Link>
                      <button
                        onClick={() => handleDelete(channel.id, channel.name)}
                        className="bg-red-600 hover:bg-red-700 px-2 py-1 rounded text-xs"
                      >
                        Eliminar
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {channels.length === 0 && (
          <div className="text-center py-12 text-gray-400">
            <p className="text-lg mb-4">No hay canales agregados</p>
            <Link to="/admin/add-channel" className="bg-red-600 hover:bg-red-700 px-6 py-3 rounded">
              Agregar Primer Canal
            </Link>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
